#include <iostream>
#include <queue>

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 30) return 1;
    std::queue<int> values;
    for (std::size_t i = 0; i < count; ++i) { int value{}; if (!(std::cin >> value)) return 1; values.push(value); }
    bool first = true;
    while (!values.empty()) { if (!first) std::cout << ' '; first = false; std::cout << values.front(); values.pop(); }
    std::cout << '\n';
}
